#nullable enable // autogenerated

using MVZ2.GameContent.Damages;
using MVZ2.Vanilla.Audios;
using MVZ2.Vanilla.Callbacks;
using MVZ2.Vanilla.Entities;
using MVZ2.Vanilla.Properties;
using MVZ2Logic.Entities;
using PVZEngine;
using PVZEngine.Callbacks;
using PVZEngine.Definitions;
using PVZEngine.Entities;
using PVZEngine.Modifiers;
using UnityEngine;

namespace MVZ2.GameContent.Enemies
{
    [AutoEntityBehaviourDefinition(VanillaEntityBehaviourNames.enemySelfRevival)]
    public class EnemySelfRevivalBehaviour : EntityBehaviourDefinition
    {
        public EnemySelfRevivalBehaviour(string nsp, string name) : base(nsp, name)
        {
            AddModifier(new BooleanModifier(LogicEnemyProps.ASSUME_ALIVE, PROP_ASSUME_ALIVE));
            AddTrigger(VanillaLevelCallbacks.PRE_ENEMY_FAINT, PreEnemyFaintCallback);
        }
        public override void Update(Entity entity)
        {
            base.Update(entity);
            SetAssumeAlive(entity, GetReviveTimes(entity) >= 0);
        }
        private void PreEnemyFaintCallback(EntityCallbackParams param, CallbackResult result)
        {
            var entity = param.entity;
            if (!entity.HasBehaviour(this))
                return;
            var fatalOutput = entity.GetLethalDeathInfo();
            if (fatalOutput != null && fatalOutput.HasEffect(VanillaDamageEffects.NO_REVIVAL))
            {
                return;
            }
            var reviveTimes = GetReviveTimes(entity);
            if (reviveTimes <= 0)
                return;
            entity.Revive();
            entity.Health = Mathf.Max(0, entity.Health);
            entity.HealEffects(entity.GetMaxHealth(), entity);
            SetReviveTimes(entity, reviveTimes - 1);

            var stunSeconds = GetReviveStunSeconds(entity);
            if (stunSeconds > 0)
            {
                entity.Stun(Ticks.FromSeconds(stunSeconds));
            }
            entity.PlaySound(VanillaSoundID.revived);

            result.SetFinalValue(false);
        }
        public static bool IsAssumeAlive(Entity entity) => entity.GetBehaviourField<bool>(PROP_ASSUME_ALIVE);
        public static void SetAssumeAlive(Entity entity, bool value) => entity.SetBehaviourField(PROP_ASSUME_ALIVE, value);
        public static int GetReviveTimes(Entity entity) => entity.GetBehaviourField<int>(PROP_REVIVE_TIMES);
        public static void SetReviveTimes(Entity entity, int value) => entity.SetBehaviourField(PROP_REVIVE_TIMES, value);
        public static float GetReviveStunSeconds(Entity entity) => entity.GetBehaviourField<float>(PROP_REVIVE_STUN_SECONDS);
        public static void SetReviveStunSeconds(Entity entity, float value) => entity.SetBehaviourField(PROP_REVIVE_STUN_SECONDS, value);
        public static readonly VanillaEntityPropertyMeta<bool> PROP_ASSUME_ALIVE = new VanillaEntityPropertyMeta<bool>("assume_alive");
        public static readonly VanillaEntityPropertyMeta<int> PROP_REVIVE_TIMES = new VanillaEntityPropertyMeta<int>("revive_times");
        public static readonly VanillaEntityPropertyMeta<float> PROP_REVIVE_STUN_SECONDS = new VanillaEntityPropertyMeta<float>("revive_stun_seconds");
    }
}
